Here's how to handle draft persistence using MAUI's lifecycle events and `Preferences`:

**1. In your `NotePage.xaml.cs`:**

```csharp
public partial class NotePage : ContentPage
{
    private const string DraftKey = "NoteDraft";

    public NotePage()
    {
        InitializeComponent();

        // Subscribe to lifecycle events
        App.Current.Windows[0].Resumed += OnResumed;
        App.Current.Windows[0].Stopped += OnStopped;
        App.Current.Windows[0].Deactivated += OnDeactivated;
    }

    private void OnDeactivated(object sender, EventArgs e)
    {
        SaveDraft();
    }

    private void OnStopped(object sender, EventArgs e)
    {
        SaveDraft();
    }

    private void OnResumed(object sender, EventArgs e)
    {
        RestoreDraft();
    }

    private void SaveDraft()
    {
        Preferences.Set(DraftKey, NoteEditor.Text ?? string.Empty);
    }

    private void RestoreDraft()
    {
        string draft = Preferences.Get(DraftKey, string.Empty);
        if (!string.IsNullOrEmpty(draft))
            NoteEditor.Text = draft;
    }

    // Restore on first load too
    protected override void OnAppearing()
    {
        base.OnAppearing();
        RestoreDraft();
    }

    // Clean up to avoid leaks
    protected override void OnDisappearing()
    {
        base.OnDisappearing();
        App.Current.Windows[0].Resumed -= OnResumed;
        App.Current.Windows[0].Stopped -= OnStopped;
        App.Current.Windows[0].Deactivated -= OnDeactivated;
    }

    // Call this when the user explicitly saves/discards
    public void ClearDraft()
    {
        Preferences.Remove(DraftKey);
    }
}
```

**2. In your `NotePage.xaml`, give the editor a name:**

```xml
<Editor x:Name="NoteEditor"
        Placeholder="Start typing your note..." />
```

**Key points:**

| Event | When it fires | Why use it |
|---|---|---|
| `Deactivated` | App loses focus | Catches quick app-switches |
| `Stopped` | App goes to background | Main save point |
| `Resumed` | App returns to foreground | Restore point |

- **`Preferences`** is ideal for small text. For larger drafts, use `SecureStorage` or write to a file via `FileSystem.AppDataDirectory`.
- Always **unsubscribe** from events in `OnDisappearing` to prevent memory leaks.
- Call `ClearDraft()` when the user intentionally saves or discards the note.
